import json
import psycopg2
import boto3
import logging
import os
import zipfile
import pandas as pd
from io import BytesIO
logger = logging.getLogger()
logger.setLevel(logging.INFO)
s3 = boto3.client("s3")
def archive(filedata,conn,curr):
    filename=filedata[0]
    file=filename.split(".")[0]
    filekey=filedata[4]
    bucketname=filedata[1]
    path=filekey.split("/")
    datetime=filedata[6].replace(" ","").replace(":","").replace("-","")
    pathbroke=''
    count=0
    for i in range(len(path)):
        if path[i]=='Land':
            count=i
            break
        pathbroke=f"{pathbroke}{path[i]}/"
    count+=1
    archpath=f"{pathbroke}Archive/"
    for i in range(count,len(path)-1):
        archpath=f"{archpath}{path[i]}/"
    archpath=f"{archpath}{file}/{datetime}/{filename}"
    copy_source = {
        'Bucket': bucketname,
        'Key': filekey
    }
    
    s3.copy_object(
        Bucket=bucketname,
        CopySource=copy_source,
        Key=archpath
    )
    logger.info(f"{filekey} moved to archive")
    delmark = s3.delete_object(
        Bucket=bucketname,
        Key=filekey
    )
    logger.warning(f"Deleted file at Land: {delmark}")
    logger.info(f"Archived at path: {archpath}")